INSERT INTO blog_posts (title, slug, content, excerpt, meta_description, status) VALUES
('How to Choose the Right Diaper Size for Your Baby', 'choosing-right-diaper-size',
 '<h2>Finding the Perfect Fit</h2><p>Choosing the right diaper size is crucial for your baby''s comfort and to prevent leaks.</p><h3>Size by Weight</h3><ul><li><strong>Newborn:</strong> Up to 4.5 kg</li><li><strong>Size 1:</strong> 2-5 kg</li><li><strong>Size 2:</strong> 3-8 kg</li><li><strong>Size 3:</strong> 4-9 kg</li><li><strong>Size 4:</strong> 7-18 kg</li></ul><h3>Signs the Diaper is Too Small</h3><p>Red marks on thighs/waist, frequent leaks, or difficulty fastening tabs mean it is time to size up.</p>',
 'A comprehensive guide to finding the perfect diaper size for your baby.',
 'Guide to choosing the right diaper size for your baby.', 'published'),

('Essential Baby Bath Products Every Parent Needs', 'essential-baby-bath-products',
 '<h2>Making Bath Time Safe and Fun</h2><p>Bath time is a special bonding moment. Having the right products makes all the difference.</p><h3>Must-Have Products</h3><ul><li>Baby Shampoo (tear-free)</li><li>Baby Body Wash (pH-balanced)</li><li>Baby Lotion</li><li>Soft Washcloths</li><li>Hooded Towels</li></ul>',
 'Everything you need for a safe and enjoyable baby bath time routine.',
 'Essential baby bath products guide for new parents.', 'published'),

('Top 5 Baby Feeding Tips for New Parents', 'baby-feeding-tips-new-parents',
 '<h2>Nourishing Your Little One</h2><p>Feeding your baby can feel overwhelming at first, but with these tips, you will feel more confident.</p><h3>1. Follow Your Baby''s Cues</h3><p>Watch for hunger signs like lip smacking and rooting.</p><h3>2. Burp Frequently</h3><p>Burp after every 2-3 ounces during bottle feeding.</p><h3>3. Sterilize Equipment</h3><p>Keep bottles clean, especially in the first few months.</p>',
 'Expert feeding tips to help new parents navigate nutrition needs.',
 'Top feeding tips for new parents.', 'published');
